s = "I love leetcode"
w=10

def splitter(s, w):
    words = s.split()
    global count
    count = 0

    def s(i):
        global count
        if i == len(words):
            return []

        for k in range(i, len(words)+1):
            if len(' '.join(words[i: k+1])) > w:
                break
        cur = ' '.join(words[i: k])
        count = count + 1
        n = count + (len(words) - k)

        return [cur + ' ' + '({0}/{1})'.format(count, n)] + s(k)

    return s(0)

print(splitter(s, w))
